    COALESCE(NULLIF(BTRIM(shelf_raw), ''), 'UNASSIGNED') AS shelf,
    CASE
      WHEN BTRIM(COALESCE(row_raw, '')) = '' THEN 0
      WHEN UPPER(BTRIM(row_raw)) = 'FLOOR' THEN 0
      WHEN BTRIM(row_raw) ~ '^-?\d+$'
        THEN GREATEST(0, BTRIM(row_raw)::integer)
      ELSE 0
    END AS floor
  FROM imported
  WHERE BTRIM(COALESCE(row_raw, '')) <> ''
),
matched_jobs AS (
  SELECT wo.reference_id, n.shelf, n.floor
  FROM normalized n
  JOIN public.work_orders wo
    ON wo.reference_id = n.job_id
),
distinct_locations AS (
  SELECT DISTINCT shelf, floor
  FROM matched_jobs
),
upsert_locations AS (
  INSERT INTO public.locations(location_code, shelf, floor, is_active)
  SELECT
    'import_' || floor::text || '_' || regexp_replace(lower(shelf), '[^a-z0-9]+', '_', 'g') AS location_code,
    shelf,
    floor,
    true
  FROM distinct_locations
  ON CONFLICT (floor, LOWER(BTRIM(shelf)))
  DO UPDATE SET is_active = EXCLUDED.is_active
  RETURNING location_id, shelf, floor
),
resolved AS (
  SELECT
    mj.reference_id,
    l.location_id
  FROM matched_jobs mj
  JOIN public.locations l
    ON l.floor = mj.floor
   AND LOWER(BTRIM(l.shelf)) = LOWER(BTRIM(mj.shelf))
)
UPDATE public.work_orders wo
SET location_id = r.location_id,
    updated_at = now()
FROM resolved r
WHERE wo.reference_id = r.reference_id;
